type GateStoreCall =
	| { kind: "updateSignalVerification"; signalId: string; update: any }
	| { kind: "updateGateStatus"; goalId: string; gateId: string; status: string };

function makeLifecycleStateDir(): string {
	const stateDir = path.join(lifecycleRoot, String(++lifecycleSequence).padStart(2, "0"), "state");
	fs.mkdirSync(stateDir, { recursive: true });
	return stateDir;
}

function makeHarness(_t: TestContext) {
	return makeHarnessForStateDir(makeLifecycleStateDir());
}

function makeHarnessForStateDir(stateDir: string) {
	const gateStoreCalls: GateStoreCall[] = [];
	const broadcasts: Array<{ goalId: string; event: any }> = [];
	const notifications: Array<{ goalId: string; message: string }> = [];
	const gateStore = {
		updateSignalVerification: (signalId: string, update: any) => {
			gateStoreCalls.push({ kind: "updateSignalVerification", signalId, update });
		},
		updateGateStatus: (goalId: string, gateId: string, status: string) => {
			gateStoreCalls.push({ kind: "updateGateStatus", goalId, gateId, status });
		},
		getGate: () => undefined,
		getGatesForGoal: () => [],
	} as any;
	const harness = new VerificationHarness(
		stateDir,
		gateStore,
		(goalId, event) => broadcasts.push({ goalId, event }),
		ROLE_STORE_ADAPTER as any,
		undefined,
		undefined,
		undefined,
		undefined,
		undefined,
		undefined,
	);
	harness.setTeamLeadNotifier((goalId, message) => notifications.push({ goalId, message }));

	return { stateDir, harness, gateStoreCalls, broadcasts, notifications };
}

function persistActive(stateDir: string, verification: ActiveVerification | any): void {
	fs.writeFileSync(
		path.join(stateDir, "active-verifications.json"),
		JSON.stringify({ verifications: [verification] }, null, 2),
	);
}

function latestSignalUpdate(calls: GateStoreCall[]): any {
	return [...calls]
		.reverse()
		.find((call): call is Extract<GateStoreCall, { kind: "updateSignalVerification" }> => call.kind === "updateSignalVerification")
		?.update;
}

function latestGateStatus(calls: GateStoreCall[]): string | undefined {
	return [...calls]
		.reverse()
		.find((call): call is Extract<GateStoreCall, { kind: "updateGateStatus" }> => call.kind === "updateGateStatus")
		?.status;
}

function stepByName(update: any, name: string): any {
	return update?.steps?.find((step: any) => step.name === name);
}

function notificationText(notifications: Array<{ message: string }>): string {
	return notifications.map(n => n.message).join("\n---\n");
}

function deferred<T = void>() {
	let resolve!: (value: T | PromiseLike<T>) => void;
	let reject!: (reason?: any) => void;
	const promise = new Promise<T>((res, rej) => { resolve = res; reject = rej; });
	return { promise, resolve, reject };
}

function spawnFixtureChild(mode: string, args: readonly string[] = []): ChildProcess & { pid: number } {
	const child = spawn(process.execPath, [immutableCommandFile, mode, ...args], {
		stdio: "ignore",
		windowsHide: true,
	}) as ChildProcess & { pid?: number };
	assert.ok(child.pid, `${MARKER}: failed to start child process for lifecycle test`);
	childClosePromises.set(child, new Promise<void>((resolve) => child.once("close", () => resolve())));
	return child as ChildProcess & { pid: number };
}

function waitForExit(child: ChildProcess, timeoutMs: number): Promise<boolean> {
	if (child.exitCode !== null || child.signalCode !== null) return Promise.resolve(true);
	return new Promise((resolve) => {
		const timer = setTimeout(() => {
			child.off("exit", onExit);
			resolve(false);
		}, timeoutMs);
		const onExit = () => {
			clearTimeout(timer);
			resolve(true);
		};
		child.once("exit", onExit);
	});
}

function isPidAliveForTest(pid: number): boolean {
	if (!Number.isFinite(pid) || pid <= 0) return false;
	try {
		process.kill(pid, 0);
		return true;
	} catch (err: any) {
		return err?.code === "EPERM";
	}
}

async function waitForPidExit(pid: number, timeoutMs: number): Promise<boolean> {
	const deadline = Date.now() + timeoutMs;
	while (Date.now() < deadline) {
		if (!isPidAliveForTest(pid)) return true;
		await sleep(50);
	}
	return !isPidAliveForTest(pid);
}

function killPidBestEffort(pid: number): void {
	if (!isPidAliveForTest(pid)) return;
	try { killTreeByPid(pid, "SIGKILL"); } catch { /* best-effort */ }
	try { process.kill(pid, "SIGKILL"); } catch { /* already gone */ }
}

async function cleanupChild(child: ChildProcess): Promise<void> {
	if (child.exitCode === null && child.signalCode === null) {
		try { child.kill("SIGKILL"); } catch { /* already gone */ }
	}
	const closePromise = childClosePromises.get(child);
	if (closePromise) await closePromise;
	child.removeAllListeners();
}

function sleep(ms: number): Promise<void> {
	return new Promise(resolve => setTimeout(resolve, ms));
}

async function waitForCondition<T>(label: string, predicate: () => T | undefined | null | false, timeoutMs = 3_000, intervalMs = 25): Promise<T> {
	const deadline = Date.now() + timeoutMs;
	let lastError: unknown;
	while (Date.now() < deadline) {
		try {
			const value = predicate();
			if (value) return value;
		} catch (err) {
			lastError = err;
		}
		await sleep(intervalMs);
	}
	assert.fail(`${MARKER}: timed out waiting for ${label}${lastError instanceof Error ? ` (${lastError.message})` : ""}`);
}

function writeFixtureFiles(root: string, files: Readonly<Record<string, string>>): void {
	fs.mkdirSync(root, { recursive: true });
	for (const [name, content] of Object.entries(files)) fs.writeFileSync(path.join(root, name), content);
}

function diagnosticFixture(
	stateDir: string,
	signalId: string,
	contents: { out?: string; err?: string; exit?: string } = {},
) {
	const diagDir = path.join(stateDir, "verifications", signalId);
	const outFile = path.join(diagDir, "stdout.log");
	const errFile = path.join(diagDir, "stderr.log");
	const exitFile = path.join(diagDir, "exit.txt");
	const pidFile = path.join(diagDir, "process.pid");
	const heartbeatFile = path.join(diagDir, "heartbeat.json");
	const files: Record<string, string> = {};
	if (contents.out !== undefined) files["stdout.log"] = contents.out;
	if (contents.err !== undefined) files["stderr.log"] = contents.err;
	if (contents.exit !== undefined) files["exit.txt"] = contents.exit;
	writeFixtureFiles(diagDir, files);
	return { diagDir, outFile, errFile, exitFile, pidFile, heartbeatFile };
}

function writeIdentityFile(file: string, pid: number, nonce: string): void {
	writeFixtureFiles(path.dirname(file), { [path.basename(file)]: `${pid}\n${nonce}\n` });
}

function writeIdentityEvidence(pidFile: string, heartbeatFile: string, pid: number, nonce: string): void {
	if (path.dirname(pidFile) !== path.dirname(heartbeatFile)) throw new Error("identity fixture files must share a directory");
	writeFixtureFiles(path.dirname(pidFile), {
		[path.basename(pidFile)]: `${pid}\n${nonce}\n`,
		[path.basename(heartbeatFile)]: JSON.stringify({ pid, nonce, ts: Math.floor(Date.now() / 1000) }) + "\n",
	});
}

function scheduleIdentityEvidence(
	pidFile: string,
	heartbeatFile: string,
	pid: number,
	nonce: string,
	delayMs: number,
): Promise<void> {
	return new Promise((resolve) => {
		setTimeout(() => {
			try { writeIdentityEvidence(pidFile, heartbeatFile, pid, nonce); }
			catch { /* test cleanup may have run */ }
			resolve();
		}, delayMs);
	});
}

function loadActiveVerifications(stateDir: string): any[] {
	try {
		return JSON.parse(fs.readFileSync(path.join(stateDir, "active-verifications.json"), "utf8")).verifications ?? [];
	} catch {
		return [];
	}
}

function clearKillRetryTimers(harness: any): void {
	const timers: Map<string, NodeJS.Timeout> | undefined = harness._commandKillRetryTimers;
	for (const timer of timers?.values?.() ?? []) clearTimeout(timer);
	timers?.clear?.();
}

function shellQuotedPath(value: string): string {
	return `"${value.replace(/\\/g, "/").replace(/"/g, '\\"')}"`;
}

function fixtureShellCommand(mode: string, args: readonly string[] = []): string {
	return [process.execPath, immutableCommandFile, mode, ...args].map(shellQuotedPath).join(" ");
}

function commandStepFixture(args: {
	name: string;
	startedAt: number;
	pid?: number;
	timeoutSec?: number;
	outFile?: string;
	errFile?: string;
	exitFile?: string;
	identityFile?: string;
	nonce?: string;
	containerId?: string;
	heartbeatFile?: string;
	processStartToken?: string;
}): any {
	return {
		...COMMAND_STEP_TEMPLATE,
		name: args.name,
		startedAt: args.startedAt,
		startTimeMs: args.startedAt,
		pid: args.pid,
		timeoutSec: args.timeoutSec ?? COMMAND_STEP_TEMPLATE.timeoutSec,
		outFile: args.outFile,
		errFile: args.errFile,
		exitFile: args.exitFile,
		commandCwd: path.dirname(args.outFile ?? args.errFile ?? args.exitFile ?? args.identityFile ?? process.cwd()),
		// Proposed persistent-command identity fields, mirroring bash_bg's pidfile+nonce contract.
		pidFile: args.identityFile,
		nonce: args.nonce,
		heartbeatFile: args.heartbeatFile,
		processStartToken: args.processStartToken,
		containerId: args.containerId,
	};
}

function activeVerification(signalId: string, steps: any[], startedAt = Date.now()): ActiveVerification | any {
	return {
		...ACTIVE_VERIFICATION_TEMPLATE,
		signalId,
		startedAt,
		steps,
	};
}

test("command step settles from process exit when inherited stdio delays close", async (t) => {
	if (process.platform === "win32" && !GIT_BASH) {
		t.skip("requires Git Bash background-job semantics on Windows");
		return;
	}
	const { stateDir, harness } = makeHarness(t);
	const workDir = path.join(stateDir, "stdio-close-delay-work");
	fs.mkdirSync(workDir, { recursive: true });
	const holderPidFile = path.join(workDir, "stdio-holder.pid");
	const shellQuote = (value: string) => `'${value.replace(/\\/g, "/").replace(/'/g, `'\"'\"'`)}'`;
	const holderCommand = fixtureShellCommand("holder", [holderPidFile]);
	const command = `${holderCommand} & __bobbit_i=0; while [ ! -s ${shellQuote(holderPidFile)} ] && [ "$__bobbit_i" -lt 500 ]; do __bobbit_i=$((__bobbit_i + 1)); sleep 0.02; done; echo stdio-close-delay-parent-exiting; exit 0`;

	let holderPid = 0;
	const stepPromise = (harness as any).runCommandStep(command, workDir, 30, false, undefined, undefined, undefined);
	try {
		holderPid = await waitForCondition("stdio holder pid", () => {
			if (!fs.existsSync(holderPidFile)) return false;
			const pid = Number(fs.readFileSync(holderPidFile, "utf8"));
			return Number.isFinite(pid) && pid > 0 && isPidAliveForTest(pid) ? pid : false;
		}, 10_000, 25);

		// The command step's own timeout guards a real hang. A second short
		// wall-clock race here made CPU starvation beat the exit/close callback
		// even though the lifecycle result was already inevitable.
		const result = await stepPromise as { passed: boolean; output: string };
		assert.equal(result.passed, true, `${MARKER}: the exited command should be treated as the authoritative result even when a descendant holds stdio open.`);
		assert.match(result.output, /stdio-close-delay-parent-exiting/, `${MARKER}: output written before the immediate process exit should be retained.`);
		assert.match(result.output, /stdio did not close/i, `${MARKER}: delayed-close fallback should explain why Bobbit finalized from process exit.`);
		if (process.platform !== "win32") {
			assert.equal(
				await waitForPidExit(holderPid, 5_000),
				true,
				`${MARKER}: delayed-stdio descendants should be reaped when Bobbit finalizes from process exit.`,
			);
		}
	} finally {
		killPidBestEffort(holderPid);
		await waitForPidExit(holderPid, 5_000);
		await stepPromise.catch(() => undefined);
	}
});

test("resume does not trust or kill an alive PID when the pidfile identity does not match", async (t) => {
	const { stateDir, harness, gateStoreCalls } = makeHarness(t);
	const child = spawnFixtureChild("idle");
	try {
		const startedAt = Date.now();
		const pidFile = path.join(stateDir, "identity", "foreign.pid");
		writeIdentityFile(pidFile, child.pid, "foreign-nonce");

		persistActive(stateDir, activeVerification("sig-foreign-pid", [commandStepFixture({
			name: "Foreign PID",
			startedAt,
			pid: child.pid,
			timeoutSec: 0.2,
			identityFile: pidFile,
			nonce: "expected-nonce",
		})], startedAt));

		await harness.resumeInterruptedVerifications();
		const exited = await waitForExit(child, 250);
		const update = latestSignalUpdate(gateStoreCalls);
		const step = stepByName(update, "Foreign PID");

		assert.equal(
			exited,
			false,
			`${MARKER}: resume must not kill an unrelated live process when the persisted pidfile/nonce does not prove identity.`,
		);
		assert.notEqual(
			latestGateStatus(gateStoreCalls),
			"failed",
			`${MARKER}: an unverified PID after restart should leave the gate retryable/pending, not failed as a command verdict.`,
		);
		assert.notEqual(
			step?.status,
			"failed",
			`${MARKER}: an unverified PID should not be persisted as a failed command step.`,
		);
	} finally {
		await cleanupChild(child);
	}
});

test("alive resumed command that dies without durable status remains restart-interrupted and pending", async (t) => {
	const { stateDir, harness, gateStoreCalls, notifications } = makeHarness(t);
	const child = spawnFixtureChild("exit-after-delay", ["80"]);
	try {
		const startedAt = Date.now();
		const { outFile, errFile, exitFile, pidFile } = diagnosticFixture(stateDir, "sig-dies-without-status", {
			out: "probe:started\n",
			err: "",
		});
		writeIdentityFile(pidFile, child.pid, "matching-nonce");

		persistActive(stateDir, activeVerification("sig-dies-without-status", [commandStepFixture({
			name: "Dies without status",
			startedAt,
			pid: child.pid,
			timeoutSec: 2,
			outFile,
			errFile,
			exitFile,
			identityFile: pidFile,
			nonce: "matching-nonce",
		})], startedAt));

		await harness.resumeInterruptedVerifications();
		const update = latestSignalUpdate(gateStoreCalls);
		const step = stepByName(update, "Dies without status");
		const notices = notificationText(notifications);

		assert.equal(
			latestGateStatus(gateStoreCalls),
			"pending",
			`${MARKER}: a command that died after restart without a durable exit/status file should leave the gate pending for re-signal.`,
		);
		assert.equal(
			step?.status,
			"waiting",
			`${MARKER}: no durable command verdict should be represented as restart-interrupted/waiting, not failed.`,
		);
		assert.match(
			step?.output ?? "",
			/no command verdict was obtained|durable command exit status|re-signal/i,
			`${MARKER}: retryable interruption diagnostics should say no command verdict was obtained.`,
		);
		assert.doesNotMatch(
			`${step?.output ?? ""}\n${notices}`,
			/did not produce an exit code \(timeout or process died after restart\)/i,
			`${MARKER}: a post-restart no-status death must not be labelled as a failed command verdict.`,
		);
	} finally {
		await cleanupChild(child);
	}
});

